const CHEMISTRY_AQA_PRACTICE = {
  'P1': {
    name: 'Physical Chemistry I',
    questions: [
      { q: 'State the number of protons, neutrons, and electrons in an atom of calcium-40.', marks: 1, markScheme: '20 protons, 20 neutrons, 20 electrons (1).' },
      { q: 'Write the electron configuration of a sulfur atom using sub-shell notation.', marks: 1, markScheme: '1s\u00b2 2s\u00b2 2p\u2076 3s\u00b2 3p\u2074 (1).' },
      { q: 'Define the term "isotope".', marks: 1, markScheme: 'Atoms of the same element with the same number of protons but different numbers of neutrons (1).' },
      { q: 'A sample of chlorine contains 75.8% chlorine-35 and 24.2% chlorine-37. Calculate the relative atomic mass.', marks: 2, markScheme: 'Ar = (0.758 \u00d7 35) + (0.242 \u00d7 37) = 26.53 + 8.95 (1) = 35.5 (1).' },
      { q: 'Explain why neon has a higher first ionisation energy than sodium.', marks: 2, markScheme: 'Neon has a higher nuclear charge than Na with the same number of electron shells / similar shielding (1). The outer electron is held more tightly (1).' },
      { q: 'Define "first ionisation energy".', marks: 2, markScheme: 'Energy required to remove one electron (1) from each atom in one mole of gaseous atoms (1).' },
      { q: 'Explain why the second ionisation energy of sodium is much larger than the first.', marks: 2, markScheme: 'Second electron removed from a full inner shell closer to the nucleus with less shielding (1). Much greater effective nuclear charge so more energy needed (1).' },
      { q: 'State and explain the shape of a BF\u2083 molecule.', marks: 2, markScheme: 'Trigonal planar (1). Three bonding pairs repel equally at 120\u00b0, no lone pairs on B (1).' },
      { q: 'Draw a dot-and-cross diagram for magnesium oxide. Show the charges on the ions.', marks: 2, markScheme: 'Diagram showing transfer of 2 electrons from Mg to O giving Mg\u00b2\u207a [2,8] and O\u00b2\u207b [2,8] (1). Correct charges shown (1).' },
      { q: 'Explain, in terms of bonding, why sodium chloride conducts electricity when molten but not when solid.', marks: 2, markScheme: 'Solid: ions in fixed positions in lattice, cannot move (1). Molten: ions free to move and carry charge (1).' },
      { q: 'Describe the bonding in a molecule of carbon dioxide and state its shape.', marks: 2, markScheme: 'Two C=O double bonds / two shared pairs per bond (1). Linear, bond angle 180\u00b0 (1).' },
      { q: 'Explain why water has a higher boiling point than hydrogen sulfide.', marks: 3, markScheme: 'Water has hydrogen bonding due to highly polar O-H bond (1). Lone pairs on O attract \u03b4+ H of adjacent molecules (1). H\u2082S has only weaker London forces / dipole-dipole as S is less electronegative (1).' },
      { q: 'State and explain the shape of the ammonium ion NH\u2084\u207a.', marks: 2, markScheme: 'Tetrahedral, bond angle 109.5\u00b0 (1). Four bonding pairs repel equally with no lone pairs on N (1).' },
      { q: 'Explain why the boiling points of the noble gases increase from He to Xe.', marks: 2, markScheme: 'Noble gases have only London dispersion forces (1). More electrons \u2192 larger, more polarisable electron cloud \u2192 stronger London forces (1).' },
      { q: 'State what is meant by a "dative covalent bond" and give one example.', marks: 2, markScheme: 'One atom provides both electrons in the shared pair (1). Example: NH\u2084\u207a or CO or Al\u2082Cl\u2086 (1).' },
      { q: 'Explain why metallic bonding leads to high electrical conductivity.', marks: 2, markScheme: 'Lattice of positive metal ions surrounded by delocalised electrons (1). Delocalised electrons free to move, carrying charge (1).' },
      { q: 'State and explain the trend in electronegativity across Period 3.', marks: 2, markScheme: 'Electronegativity increases across Period 3 Na to Cl (1). Nuclear charge increases, atomic radius decreases, bonding electrons attracted more strongly (1).' },
      { q: 'Define "enthalpy of formation" and write the equation for the formation of ethanol.', marks: 2, markScheme: 'Enthalpy change when 1 mole of compound formed from elements in standard states (1). 2C(s) + 3H\u2082(g) + \u00bdO\u2082(g) \u2192 C\u2082H\u2085OH(l) (1).' },
      { q: 'State Hess\'s law.', marks: 1, markScheme: 'The total enthalpy change for a reaction is independent of the route taken, provided initial and final conditions are the same (1).' },
      { q: 'Calculate the enthalpy change for CH\u2084 + 2O\u2082 \u2192 CO\u2082 + 2H\u2082O using mean bond enthalpies: C-H = 412, O=O = 496, C=O = 743, O-H = 463 kJ/mol.', marks: 3, markScheme: 'Bonds broken: 4(412) + 2(496) = 2640 kJ (1). Bonds formed: 2(743) + 4(463) = 3338 kJ (1). \u0394H = 2640 \u2212 3338 = \u2212698 kJ/mol (1).' },
      { q: 'State what is meant by "mean bond enthalpy".', marks: 2, markScheme: 'Average energy to break one mole of a particular type of covalent bond (1) in the gaseous state, averaged across different compounds (1).' },
      { q: 'Using Hess\'s law and enthalpies of combustion, calculate \u0394Hf of methane. Data: \u0394Hc[C] = \u2212393, \u0394Hc[H\u2082] = \u2212286, \u0394Hc[CH\u2084] = \u2212890 kJ/mol.', marks: 3, markScheme: '\u0394Hf = \u0394Hc(elements) \u2212 \u0394Hc(compound) (1). = [\u2212393 + 2(\u2212286)] \u2212 (\u2212890) (1). = \u2212393 \u2212 572 + 890 = \u221275 kJ/mol (1).' },
      { q: 'Explain why the enthalpy of atomisation of Cl\u2082 is half the Cl-Cl bond enthalpy.', marks: 2, markScheme: 'Atomisation forms 1 mole of gaseous atoms from element in standard state (1). Breaking 1 mole Cl\u2082 produces 2 moles Cl atoms, so atomisation is half (1).' },
      { q: 'Define "electron affinity" and state whether the first electron affinity of chlorine is exothermic or endothermic.', marks: 2, markScheme: 'Enthalpy change when 1 electron is added to each atom in 1 mole of gaseous atoms forming 1 mole of gaseous 1\u2212 ions (1). First EA of Cl is exothermic (1).' },
      { q: 'Using successive ionisation energy data (578, 1817, 2745, 11578 kJ/mol), determine which group the element belongs to.', marks: 2, markScheme: 'Large jump between 3rd and 4th ionisation energies (1). Three outer electrons so Group 3/13 (1).' },
      { q: 'Explain why phosphorus can form PCl\u2085 but nitrogen cannot form NCl\u2085.', marks: 2, markScheme: 'P has available 3d orbitals for expanded octet (1). N is in Period 2 with no d orbitals, cannot exceed octet (1).' },
      { q: 'Explain why diamond has a very high melting point but does not conduct electricity.', marks: 2, markScheme: 'Each C bonded to 4 others in rigid tetrahedral giant covalent structure; many strong C-C bonds to break (1). All outer electrons in bonding, none free to move (1).' },
      { q: 'Compare the structures of diamond and graphite. Explain why graphite conducts electricity.', marks: 3, markScheme: 'Diamond: each C bonded to 4 others, rigid 3D structure (1). Graphite: each C bonded to 3 others in layers with delocalised electrons (1). Delocalised electrons can move between layers carrying charge (1).' },
      { q: 'Explain why the bond angle in water (104.5\u00b0) is less than in methane (109.5\u00b0).', marks: 2, markScheme: 'Water has 2 bonding pairs and 2 lone pairs on O; methane has 4 bonding pairs (1). Lone pairs repel more than bonding pairs, compressing bond angle (1).' },
      { q: 'Calculate the number of moles in 5.85 g of sodium chloride (NaCl, Mr = 58.5).', marks: 1, markScheme: 'n = m/Mr = 5.85/58.5 = 0.100 mol (1).' },
      { q: 'Calculate the volume of 0.25 mol of gas at room temperature and pressure (1 mol = 24.0 dm\u00b3).', marks: 1, markScheme: 'V = n \u00d7 24.0 = 0.25 \u00d7 24.0 = 6.0 dm\u00b3 (1).' },
      { q: 'What is the concentration of a solution containing 4.0 g of NaOH (Mr = 40.0) dissolved in 500 cm\u00b3 of water?', marks: 2, markScheme: 'n = 4.0/40.0 = 0.10 mol (1). c = 0.10/0.500 = 0.20 mol dm\u207b\u00b3 (1).' },
      { q: '25.0 cm\u00b3 of 0.100 mol dm\u207b\u00b3 NaOH reacts with HCl. The titre is 20.0 cm\u00b3. Calculate the concentration of HCl.', marks: 3, markScheme: 'n(NaOH) = 0.0250 \u00d7 0.100 = 0.00250 mol (1). 1:1 ratio so n(HCl) = 0.00250 mol (1). c(HCl) = 0.00250/0.0200 = 0.125 mol dm\u207b\u00b3 (1).' },
      { q: 'Calculate the percentage atom economy for the production of ethanol by fermentation: C\u2086H\u2081\u2082O\u2086 \u2192 2C\u2082H\u2085OH + 2CO\u2082.', marks: 2, markScheme: 'Mr of desired product = 2 \u00d7 46 = 92; Mr of all products = 92 + 2(44) = 180 (1). % atom economy = (92/180) \u00d7 100 = 51.1% (1).' },
      { q: 'A compound has the empirical formula CH\u2082O and Mr = 60. Determine its molecular formula.', marks: 2, markScheme: 'Empirical formula mass = 12 + 2 + 16 = 30 (1). 60/30 = 2, so molecular formula = C\u2082H\u2084O\u2082 (1).' },
      { q: 'State the ideal gas equation and calculate the pressure exerted by 0.50 mol of gas in a 12.0 dm\u00b3 container at 300 K (R = 8.31 J K\u207b\u00b9 mol\u207b\u00b9).', marks: 3, markScheme: 'pV = nRT (1). p = nRT/V = (0.50 \u00d7 8.31 \u00d7 300) / (12.0 \u00d7 10\u207b\u00b3) (1). p = 1247.5 / 0.012 = 103,958 Pa \u2248 104 kPa (1).' },
      { q: 'Explain why the lattice enthalpy of MgO is much larger in magnitude than that of NaCl.', marks: 2, markScheme: 'Mg\u00b2\u207a and O\u00b2\u207b have higher charges (2+ and 2\u2212) than Na\u207a and Cl\u207b (1). Smaller ionic radii give higher charge density and stronger electrostatic attraction (1).' },
      { q: 'State and explain whether dissolving NH\u2084NO\u2083 in water (which is endothermic) will have a positive or negative entropy change for the system.', marks: 2, markScheme: 'Positive entropy change (1). Solid lattice breaks up into ions dispersed in solution, increasing disorder (1).' },
      { q: 'Explain why the ionic radius of Na\u207a is smaller than that of Na.', marks: 2, markScheme: 'Na\u207a has lost one electron, leaving fewer electrons than protons (1). Remaining electrons are pulled closer to the nucleus by the same nuclear charge (1).' },
      { q: 'Explain why the O\u00b2\u207b ion is larger than the O atom.', marks: 2, markScheme: 'O\u00b2\u207b has gained two extra electrons (1). More electron-electron repulsion causes the electron cloud to expand, same nuclear charge pulling on more electrons (1).' },
      { q: 'Define "enthalpy of combustion" and state its sign for all combustion reactions.', marks: 2, markScheme: 'The enthalpy change when 1 mole of a substance is completely burned in excess oxygen under standard conditions (1). Always negative / exothermic (1).' },
      { q: 'Calculate the enthalpy of reaction for: 2C(s) + 2H\u2082(g) \u2192 C\u2082H\u2084(g) given \u0394Hc[C] = \u2212393, \u0394Hc[H\u2082] = \u2212286, \u0394Hc[C\u2082H\u2084] = \u22121411 kJ/mol.', marks: 3, markScheme: '\u0394Hf = \u03a3\u0394Hc(reactants) \u2212 \u03a3\u0394Hc(products) (1). = [2(\u2212393) + 2(\u2212286)] \u2212 (\u22121411) (1). = \u2212786 \u2212 572 + 1411 = +53 kJ/mol (1).' },
      { q: 'Explain why the electron configuration of chromium is [Ar] 3d\u2075 4s\u00b9 rather than [Ar] 3d\u2074 4s\u00b2.', marks: 2, markScheme: 'A half-filled 3d subshell (3d\u2075) is particularly stable (1). The extra stability from having one electron in each 3d orbital outweighs the energy cost of leaving 4s half-filled (1).' },
      { q: 'State two properties of a metallic bond that explain why metals are malleable.', marks: 2, markScheme: 'Layers of metal ions can slide over each other (1). The delocalised electrons can adjust position, maintaining the metallic bonding in the new arrangement (1).' },
      { q: 'Draw a dot-and-cross diagram for PCl\u2083. State its shape and bond angle.', marks: 2, markScheme: 'P shares one pair of electrons with each of 3 Cl atoms, with 1 lone pair on P (1). Trigonal pyramidal, bond angle approximately 107\u00b0 (1).' },
      { q: 'Explain why ice is less dense than liquid water.', marks: 2, markScheme: 'In ice, each water molecule forms 4 hydrogen bonds in a rigid open tetrahedral lattice (1). This open structure has more space between molecules than liquid water, making ice less dense (1).' },
      { q: 'Calculate the number of atoms in 0.25 mol of neon (Avogadro constant = 6.022 \u00d7 10\u00b2\u00b3 mol\u207b\u00b9).', marks: 1, markScheme: '0.25 \u00d7 6.022 \u00d7 10\u00b2\u00b3 = 1.506 \u00d7 10\u00b2\u00b3 atoms (1).' },
      { q: 'What mass of carbon dioxide is produced when 10.0 g of calcium carbonate decomposes completely? CaCO\u2083 \u2192 CaO + CO\u2082 (Mr: CaCO\u2083 = 100, CO\u2082 = 44).', marks: 2, markScheme: 'n(CaCO\u2083) = 10.0/100 = 0.100 mol; 1:1 ratio so n(CO\u2082) = 0.100 mol (1). Mass = 0.100 \u00d7 44 = 4.40 g (1).' },
      { q: 'Explain why aluminium has a higher melting point than sodium in terms of metallic bonding.', marks: 2, markScheme: 'Al has 3 delocalised electrons per atom vs 1 for Na, giving stronger metallic bonding (1). Al\u00b3\u207a is smaller with higher charge density than Na\u207a, so attraction to delocalised electrons is stronger (1).' },
      { q: 'State and explain the shape of a water molecule using VSEPR theory.', marks: 2, markScheme: 'Bent / V-shaped with bond angle approximately 104.5\u00b0 (1). Two bonding pairs and two lone pairs; lone pairs repel more than bonding pairs, compressing angle below 109.5\u00b0 (1).' }
    ]
  },
  'P2': {
    name: 'Physical Chemistry II',
    questions: [
      { q: 'Define "rate of reaction".', marks: 1, markScheme: 'Change in concentration of a reactant or product per unit time (1).' },
      { q: 'State three factors that affect the rate of a chemical reaction.', marks: 1, markScheme: 'Any three from: temperature, concentration, pressure (gases), surface area, catalyst (1 for three correct).' },
      { q: 'Explain, using collision theory, why increasing temperature increases rate of reaction.', marks: 3, markScheme: 'Particles have more kinetic energy (1). More particles with energy \u2265 activation energy (1). Frequency of successful collisions increases (1).' },
      { q: 'Define "activation energy".', marks: 1, markScheme: 'The minimum energy that colliding particles must have for a successful reaction to occur (1).' },
      { q: 'Sketch a Maxwell-Boltzmann distribution and show on it how a catalyst affects the proportion of molecules that can react.', marks: 3, markScheme: 'Correct shape of curve: starts at origin, peaks, then long tail to right (1). Labelled activation energy Ea on x-axis (1). New lower Ea shown; more molecules to the right of this new Ea / greater area under curve beyond new Ea (1).' },
      { q: 'State Le Chatelier\'s principle.', marks: 1, markScheme: 'If a system at equilibrium is subjected to a change, the position of equilibrium shifts to oppose the change (1).' },
      { q: 'For the equilibrium N\u2082O\u2084(g) \u21cc 2NO\u2082(g) \u0394H = +57 kJ/mol, predict the effect of increasing temperature on the position of equilibrium.', marks: 2, markScheme: 'Equilibrium shifts to the right / towards products (1). Forward reaction is endothermic so the system absorbs the added heat to oppose the change (1).' },
      { q: 'Write the expression for Kp for the reaction: N\u2082(g) + 3H\u2082(g) \u21cc 2NH\u2083(g).', marks: 1, markScheme: 'Kp = p(NH\u2083)\u00b2 / (p(N\u2082) \u00d7 p(H\u2082)\u00b3) (1).' },
      { q: 'State what happens to the value of Kc when a catalyst is added to a system at equilibrium.', marks: 1, markScheme: 'Kc is unchanged; a catalyst affects the rate of forward and reverse reactions equally (1).' },
      { q: 'Define pH.', marks: 1, markScheme: 'pH = \u2212log\u2081\u2080[H\u207a] (1).' },
      { q: 'Calculate the pH of a 0.050 mol dm\u207b\u00b3 solution of HCl.', marks: 1, markScheme: 'pH = \u2212log(0.050) = 1.30 (1).' },
      { q: 'Calculate [H\u207a] in a solution with pH 3.40.', marks: 1, markScheme: '[H\u207a] = 10\u207b\u00b3\u00b7\u2074\u2070 = 3.98 \u00d7 10\u207b\u2074 mol dm\u207b\u00b3 (1).' },
      { q: 'Define Ka for a weak acid HA.', marks: 1, markScheme: 'Ka = [H\u207a][A\u207b] / [HA] (1).' },
      { q: 'Calculate the pH of a 0.20 mol dm\u207b\u00b3 solution of a weak acid with Ka = 4.0 \u00d7 10\u207b\u2075 mol dm\u207b\u00b3.', marks: 3, markScheme: '[H\u207a]\u00b2 = Ka \u00d7 c = 4.0 \u00d7 10\u207b\u2075 \u00d7 0.20 = 8.0 \u00d7 10\u207b\u2076 (1). [H\u207a] = 2.83 \u00d7 10\u207b\u00b3 (1). pH = \u2212log(2.83 \u00d7 10\u207b\u00b3) = 2.55 (1).' },
      { q: 'State what is meant by the ionic product of water, Kw, and give its value at 25\u00b0C.', marks: 2, markScheme: 'Kw = [H\u207a][OH\u207b] (1). Kw = 1.00 \u00d7 10\u207b\u00b9\u2074 mol\u00b2 dm\u207b\u2076 at 25\u00b0C (1).' },
      { q: 'Calculate the pH of a 0.10 mol dm\u207b\u00b3 solution of NaOH.', marks: 2, markScheme: '[OH\u207b] = 0.10; [H\u207a] = Kw/[OH\u207b] = 1.0 \u00d7 10\u207b\u00b9\u2074 / 0.10 = 1.0 \u00d7 10\u207b\u00b9\u00b3 (1). pH = \u2212log(1.0 \u00d7 10\u207b\u00b9\u00b3) = 13.0 (1).' },
      { q: 'Define "buffer solution".', marks: 1, markScheme: 'A solution that resists changes in pH when small amounts of acid or alkali are added (1).' },
      { q: 'Explain how a buffer made from CH\u2083COOH and CH\u2083COONa resists pH change when a small amount of NaOH is added.', marks: 2, markScheme: 'OH\u207b reacts with CH\u2083COOH: CH\u2083COOH + OH\u207b \u2192 CH\u2083COO\u207b + H\u2082O (1). The weak acid neutralises the added alkali, and the large reservoir of CH\u2083COOH ensures [H\u207a] changes very little (1).' },
      { q: 'Calculate the pH of a buffer containing 0.40 mol dm\u207b\u00b3 CH\u2083COOH and 0.20 mol dm\u207b\u00b3 CH\u2083COONa (Ka = 1.74 \u00d7 10\u207b\u2075).', marks: 2, markScheme: '[H\u207a] = Ka \u00d7 [acid]/[salt] = 1.74 \u00d7 10\u207b\u2075 \u00d7 0.40/0.20 = 3.48 \u00d7 10\u207b\u2075 (1). pH = \u2212log(3.48 \u00d7 10\u207b\u2075) = 4.46 (1).' },
      { q: 'Write the half-equations and overall equation for the reaction between zinc and copper(II) sulfate solution.', marks: 3, markScheme: 'Oxidation: Zn \u2192 Zn\u00b2\u207a + 2e\u207b (1). Reduction: Cu\u00b2\u207a + 2e\u207b \u2192 Cu (1). Overall: Zn + Cu\u00b2\u207a \u2192 Zn\u00b2\u207a + Cu (1).' },
      { q: 'Define "standard electrode potential".', marks: 2, markScheme: 'The EMF of a half-cell compared to a standard hydrogen electrode (1) measured under standard conditions: 298 K, 100 kPa, 1.00 mol dm\u207b\u00b3 (1).' },
      { q: 'Calculate the EMF of a cell made from Zn\u00b2\u207a/Zn (\u22120.76 V) and Cu\u00b2\u207a/Cu (+0.34 V) half-cells.', marks: 1, markScheme: 'Ecell = +0.34 \u2212 (\u22120.76) = +1.10 V (1).' },
      { q: 'State what a positive Ecell value indicates about the feasibility of a reaction.', marks: 1, markScheme: 'A positive Ecell indicates the reaction is feasible / thermodynamically possible under standard conditions (1).' },
      { q: 'Explain why a reaction with a positive Ecell may not occur in practice.', marks: 2, markScheme: 'The reaction may have a very high activation energy / be kinetically slow (1). Conditions may not be standard, changing the actual electrode potentials (1).' },
      { q: 'Determine the order of reaction with respect to A given: doubling [A] quadruples the rate.', marks: 1, markScheme: 'Order = 2 with respect to A (rate \u221d [A]\u00b2) (1).' },
      { q: 'The rate equation is rate = k[X][Y]\u00b2. State the overall order and units of k.', marks: 2, markScheme: 'Overall order = 3 (1). Units: mol\u207b\u00b2 dm\u2076 s\u207b\u00b9 (1).' },
      { q: 'Explain what is meant by the "rate-determining step" of a reaction.', marks: 1, markScheme: 'The slowest step in a multi-step mechanism that controls the overall rate of reaction (1).' },
      { q: 'A reaction A + 2B \u2192 C has rate = k[A][B]. Suggest why B does not appear as [B]\u00b2 in the rate equation.', marks: 2, markScheme: 'The rate equation is determined experimentally, not from the stoichiometric equation (1). Only one molecule of B is involved in the rate-determining step (1).' },
      { q: 'State the relationship between Gibbs free energy, enthalpy and entropy.', marks: 1, markScheme: '\u0394G = \u0394H \u2212 T\u0394S (1).' },
      { q: 'Calculate \u0394G at 298 K for a reaction where \u0394H = \u2212100 kJ/mol and \u0394S = +50 J K\u207b\u00b9 mol\u207b\u00b9.', marks: 2, markScheme: '\u0394G = \u2212100 \u2212 (298 \u00d7 0.050) = \u2212100 \u2212 14.9 (1) = \u2212114.9 kJ/mol (feasible) (1).' },
      { q: 'State the condition for a reaction to be feasible in terms of Gibbs free energy.', marks: 1, markScheme: '\u0394G must be negative (less than zero) (1).' },
      { q: 'Calculate the temperature above which a reaction with \u0394H = +150 kJ/mol and \u0394S = +200 J K\u207b\u00b9 mol\u207b\u00b9 becomes feasible.', marks: 2, markScheme: 'At \u0394G = 0: T = \u0394H/\u0394S = 150000/200 (1) = 750 K; feasible above 750 K (1).' },
      { q: 'Explain why an increase in temperature always increases the rate constant k.', marks: 2, markScheme: 'k = Ae^(\u2212Ea/RT); as T increases, \u2212Ea/RT becomes less negative (1). So the exponential term increases, meaning k increases (1).' },
      { q: 'Draw and label an enthalpy profile diagram for a catalysed and uncatalysed exothermic reaction.', marks: 3, markScheme: 'Correct enthalpy profile with reactants higher than products (1). Activation energy labelled for uncatalysed reaction (1). Lower activation energy shown for catalysed pathway (1).' },
      { q: 'State and explain the effect of diluting an equilibrium mixture on the position of equilibrium for: CH\u2083COOH(aq) \u21cc CH\u2083COO\u207b(aq) + H\u207a(aq).', marks: 2, markScheme: 'Equilibrium shifts to the right (1). Dilution decreases concentrations; the system opposes this by producing more ions (more particles in solution) / moving to the side with more moles of solute (1).' },
      { q: 'Write the expression for Kc for the esterification: CH\u2083COOH + C\u2082H\u2085OH \u21cc CH\u2083COOC\u2082H\u2085 + H\u2082O.', marks: 1, markScheme: 'Kc = [CH\u2083COOC\u2082H\u2085][H\u2082O] / ([CH\u2083COOH][C\u2082H\u2085OH]) (1).' },
      { q: 'At equilibrium, [CH\u2083COOH] = 0.33, [C\u2082H\u2085OH] = 0.33, [CH\u2083COOC\u2082H\u2085] = 0.67, [H\u2082O] = 0.67 mol dm\u207b\u00b3. Calculate Kc.', marks: 2, markScheme: 'Kc = (0.67 \u00d7 0.67) / (0.33 \u00d7 0.33) (1) = 0.4489/0.1089 = 4.12 (no units) (1).' },
      { q: 'Explain what is meant by a "half-life" in the context of reaction kinetics.', marks: 1, markScheme: 'The time taken for the concentration of a reactant to fall to half its original value (1).' },
      { q: 'State the characteristic feature of the half-life for a first-order reaction.', marks: 1, markScheme: 'The half-life is constant / independent of the initial concentration (1).' },
      { q: 'From a concentration-time graph, the concentration drops from 1.0 to 0.5 mol dm\u207b\u00b3 in 30 s and from 0.5 to 0.25 in 30 s. State the order.', marks: 1, markScheme: 'First order (constant half-life of 30 s) (1).' },
      { q: 'Explain why the enthalpy change of neutralisation of a strong acid with a strong base is approximately \u221257.1 kJ/mol regardless of which acid and base are used.', marks: 2, markScheme: 'Strong acids and bases fully dissociate, so the reaction in every case is simply H\u207a(aq) + OH\u207b(aq) \u2192 H\u2082O(l) (1). The same bond (O-H) is formed each time, releasing the same amount of energy (1).' },
      { q: 'Define "standard enthalpy of neutralisation".', marks: 2, markScheme: 'The enthalpy change when an acid and base react to form 1 mole of water (1) under standard conditions (1).' },
      { q: 'Explain why the enthalpy of neutralisation of a weak acid with a strong base is less exothermic than \u221257.1 kJ/mol.', marks: 2, markScheme: 'A weak acid is only partially dissociated (1). Some energy is used to complete the dissociation of the weak acid before neutralisation, making the overall enthalpy change less exothermic (1).' },
      { q: 'Write the half-equations for the electrolysis of molten sodium chloride at the cathode and anode.', marks: 2, markScheme: 'Cathode: Na\u207a + e\u207b \u2192 Na (1). Anode: 2Cl\u207b \u2192 Cl\u2082 + 2e\u207b (1).' },
      { q: 'State and explain the effect of increasing concentration on the rate of reaction using collision theory.', marks: 2, markScheme: 'Increasing concentration increases the number of particles per unit volume (1). This increases the frequency of collisions and hence the frequency of successful collisions (1).' },
      { q: 'A cell is set up with Fe\u00b3\u207a/Fe\u00b2\u207a (E\u00b0 = +0.77 V) and I\u2082/I\u207b (E\u00b0 = +0.54 V). Calculate Ecell and state which species is oxidised.', marks: 2, markScheme: 'Ecell = +0.77 \u2212 0.54 = +0.23 V (1). I\u207b is oxidised (more negative E\u00b0) to I\u2082, while Fe\u00b3\u207a is reduced to Fe\u00b2\u207a (1).' },
      { q: 'Explain why entropy increases when a solid dissolves in water.', marks: 2, markScheme: 'The ordered lattice structure of the solid breaks down (1). Ions/molecules become dispersed throughout the solution, increasing disorder (1).' },
      { q: 'Calculate the entropy change for a reaction where \u0394H = \u221240 kJ/mol and \u0394G = \u221252 kJ/mol at 298 K.', marks: 2, markScheme: '\u0394G = \u0394H \u2212 T\u0394S so \u0394S = (\u0394H \u2212 \u0394G)/T (1). \u0394S = (\u221240000 \u2212 (\u221252000))/298 = 12000/298 = +40.3 J K\u207b\u00b9 mol\u207b\u00b9 (1).' },
      { q: 'State and explain the effect of a catalyst on the position of equilibrium.', marks: 2, markScheme: 'A catalyst has no effect on the position of equilibrium / does not change Kc (1). It speeds up both forward and reverse reactions equally, so equilibrium is reached faster but the composition is unchanged (1).' },
      { q: 'Explain why the pH of pure water increases above 7 when the temperature is decreased below 25\u00b0C.', marks: 2, markScheme: 'The dissociation of water is endothermic; lowering temperature shifts equilibrium to the left, decreasing [H\u207a] (1). Since Kw decreases, [H\u207a] < 10\u207b\u2077 mol dm\u207b\u00b3 so pH > 7, though water is still neutral as [H\u207a] = [OH\u207b] (1).' }
    ]
  },
  'I1': {
    name: 'Inorganic Chemistry I',
    questions: [
      { q: 'State the trend in atomic radius down Group 2.', marks: 1, markScheme: 'Atomic radius increases down Group 2 (1).' },
      { q: 'Explain why barium is more reactive with water than magnesium.', marks: 2, markScheme: 'Ba has a larger atomic radius with more shielding / lower ionisation energies (1). The outer electrons are more easily lost, so Ba reacts more vigorously (1).' },
      { q: 'Write the equation for the reaction of calcium with water.', marks: 1, markScheme: 'Ca(s) + 2H\u2082O(l) \u2192 Ca(OH)\u2082(aq) + H\u2082(g) (1).' },
      { q: 'Describe the observations when magnesium is added to steam.', marks: 2, markScheme: 'Burns with a bright white flame / vigorous reaction (1). White solid (MgO) forms and hydrogen gas produced (1).' },
      { q: 'State and explain the trend in solubility of Group 2 hydroxides.', marks: 2, markScheme: 'Solubility increases down the group: Mg(OH)\u2082 sparingly soluble, Ba(OH)\u2082 soluble (1). The lattice enthalpy decreases faster than the hydration enthalpy as the cation gets larger (1).' },
      { q: 'State and explain the trend in solubility of Group 2 sulfates.', marks: 2, markScheme: 'Solubility decreases down the group: MgSO\u2084 soluble, BaSO\u2084 insoluble (1). The hydration enthalpy decreases faster than lattice enthalpy for the large sulfate anion (1).' },
      { q: 'Write the equation for the thermal decomposition of calcium carbonate.', marks: 1, markScheme: 'CaCO\u2083(s) \u2192 CaO(s) + CO\u2082(g) (1).' },
      { q: 'Explain the trend in thermal stability of Group 2 carbonates down the group.', marks: 2, markScheme: 'Thermal stability increases down the group (higher decomposition temperature) (1). Larger cations have lower charge density and polarise the carbonate ion less, making it harder to decompose (1).' },
      { q: 'State the colour of chlorine gas and write the equation for its reaction with cold dilute NaOH.', marks: 2, markScheme: 'Pale green / yellow-green (1). Cl\u2082 + 2NaOH \u2192 NaCl + NaClO + H\u2082O (1).' },
      { q: 'Define "disproportionation" and identify it in the reaction of chlorine with water.', marks: 2, markScheme: 'Disproportionation: an element is simultaneously oxidised and reduced in the same reaction (1). Cl\u2082 + H\u2082O \u21cc HClO + HCl; Cl goes from 0 to +1 (oxidation) and 0 to \u22121 (reduction) (1).' },
      { q: 'Describe the test for chloride ions using silver nitrate and ammonia.', marks: 2, markScheme: 'Add AgNO\u2083(aq) acidified with dilute HNO\u2083: white precipitate of AgCl forms (1). AgCl dissolves in dilute ammonia solution (1).' },
      { q: 'Describe the test for bromide ions using silver nitrate and ammonia.', marks: 2, markScheme: 'Add AgNO\u2083(aq) acidified with dilute HNO\u2083: cream precipitate of AgBr forms (1). AgBr dissolves in concentrated ammonia only (1).' },
      { q: 'Describe the test for iodide ions using silver nitrate and ammonia.', marks: 2, markScheme: 'Add AgNO\u2083(aq) acidified with dilute HNO\u2083: yellow precipitate of AgI forms (1). AgI is insoluble in both dilute and concentrated ammonia (1).' },
      { q: 'Explain why HCl is a strong acid but HF is a weak acid.', marks: 2, markScheme: 'The H-F bond is much stronger than the H-Cl bond (1). HCl fully dissociates in water, but HF does not because more energy is needed to break the H-F bond (1).' },
      { q: 'State the trend in boiling points of the hydrogen halides from HF to HI, explaining the anomaly at HF.', marks: 3, markScheme: 'HCl to HI: boiling point increases due to increasing London forces with more electrons (1). HF has an anomalously high boiling point (1). HF forms hydrogen bonds because F is highly electronegative, requiring more energy to overcome (1).' },
      { q: 'Write the equation for the reaction of concentrated sulfuric acid with sodium chloride.', marks: 1, markScheme: 'NaCl + H\u2082SO\u2084 \u2192 NaHSO\u2084 + HCl (1).' },
      { q: 'Explain why NaBr reacts differently with concentrated H\u2082SO\u2084 compared to NaCl.', marks: 2, markScheme: 'Br\u207b is a stronger reducing agent than Cl\u207b (1). Br\u207b can reduce H\u2082SO\u2084 to SO\u2082, producing Br\u2082 as well as HBr initially (1).' },
      { q: 'Describe what is observed when concentrated H\u2082SO\u2084 is added to KI.', marks: 3, markScheme: 'Purple/violet vapour and black solid (iodine) observed (1). Yellow solid (sulfur) may be seen; smell of rotten eggs (H\u2082S) (1). I\u207b is a strong enough reducing agent to reduce H\u2082SO\u2084 all the way to H\u2082S (1).' },
      { q: 'Explain the trend in reducing ability of halide ions from F\u207b to I\u207b.', marks: 2, markScheme: 'Reducing ability increases from F\u207b to I\u207b (1). Ionic radius increases, so outer electron is further from nucleus with more shielding, making it easier to lose an electron (1).' },
      { q: 'State the oxidation states of chlorine in NaClO.', marks: 1, markScheme: 'Na = +1, O = \u22122, so Cl = +1 (1).' },
      { q: 'Write the equation for the reaction of chlorine with hot concentrated NaOH and state the oxidation state changes.', marks: 2, markScheme: '3Cl\u2082 + 6NaOH \u2192 5NaCl + NaClO\u2083 + 3H\u2082O (1). Cl: 0 to \u22121 (reduction) and 0 to +5 (oxidation) \u2014 disproportionation (1).' },
      { q: 'State one use of chlorine in everyday life and explain the chemistry behind it.', marks: 2, markScheme: 'Water purification / making bleach (1). Cl\u2082 reacts with water to form HClO which kills bacteria by oxidation (1).' },
      { q: 'Explain why the Group 2 metal oxides are described as basic oxides.', marks: 2, markScheme: 'They react with acids to form a salt and water: MgO + 2HCl \u2192 MgCl\u2082 + H\u2082O (1). They dissolve in water to form alkaline solutions: CaO + H\u2082O \u2192 Ca(OH)\u2082 (1).' },
      { q: 'State the flame colours produced by Group 2 metal compounds: Ca, Sr, Ba.', marks: 1, markScheme: 'Ca = brick-red/orange-red, Sr = crimson/red, Ba = pale/apple green (1).' },
      { q: 'Explain why Group 2 elements have higher melting points than Group 1 elements in the same period.', marks: 2, markScheme: 'Group 2 elements have 2 delocalised electrons per atom vs 1 for Group 1 (1). Stronger metallic bonding due to higher charge on the ion and more delocalised electrons (1).' },
      { q: 'Describe how chlorine is used to make bleach. Write the relevant equation.', marks: 2, markScheme: 'Chlorine reacts with cold dilute sodium hydroxide: Cl\u2082 + 2NaOH \u2192 NaCl + NaClO + H\u2082O (1). NaClO (sodium hypochlorite) is the active bleaching agent (1).' },
      { q: 'Compare the reactions of Cl\u2082 with cold dilute NaOH and hot concentrated NaOH.', marks: 3, markScheme: 'Cold dilute: Cl\u2082 + 2NaOH \u2192 NaCl + NaClO + H\u2082O; Cl goes to \u22121 and +1 (1). Hot concentrated: 3Cl\u2082 + 6NaOH \u2192 5NaCl + NaClO\u2083 + 3H\u2082O; Cl goes to \u22121 and +5 (1). Both are disproportionation; higher temperature gives higher oxidation state of Cl (1).' },
      { q: 'State why calcium hydroxide (slaked lime) is used to treat acidic soil.', marks: 1, markScheme: 'Ca(OH)\u2082 is a base that neutralises the acid in soil, raising the pH to a level suitable for plant growth (1).' },
      { q: 'Explain, with an equation, why a precipitate forms when barium chloride is added to sodium sulfate solution.', marks: 2, markScheme: 'Ba\u00b2\u207a(aq) + SO\u2084\u00b2\u207b(aq) \u2192 BaSO\u2084(s) (1). BaSO\u2084 is insoluble, so a white precipitate forms (1).' },
      { q: 'State why dilute HCl (not H\u2082SO\u2084) is added before the silver nitrate test for halide ions.', marks: 2, markScheme: 'HCl removes interfering ions such as carbonate or sulfate which would also give precipitates with Ag\u207a (1). H\u2082SO\u2084 is not used because SO\u2084\u00b2\u207b would precipitate as Ag\u2082SO\u2084 / interfere with the test (1).' },
      { q: 'State and explain the trend in bond enthalpies of the hydrogen halides HF to HI.', marks: 2, markScheme: 'Bond enthalpy decreases from HF to HI (1). As the halogen gets larger, the bond is longer and weaker / less effective overlap of orbitals (1).' },
      { q: 'Write the equation for the reaction of magnesium with dilute sulfuric acid and describe the observation.', marks: 2, markScheme: 'Mg + H\u2082SO\u2084 \u2192 MgSO\u2084 + H\u2082 (1). Magnesium dissolves / effervescence observed as hydrogen gas is produced (1).' },
      { q: 'Explain why the thermal decomposition of MgCO\u2083 requires a lower temperature than BaCO\u2083.', marks: 2, markScheme: 'Mg\u00b2\u207a is smaller with higher charge density than Ba\u00b2\u207a (1). Mg\u00b2\u207a polarises the carbonate ion more, weakening a C-O bond and making it easier to decompose (1).' },
      { q: 'A displacement reaction occurs when chlorine water is added to potassium bromide solution. Write the equation and explain.', marks: 2, markScheme: 'Cl\u2082 + 2KBr \u2192 2KCl + Br\u2082 (1). Chlorine is a stronger oxidising agent than bromine (more electronegative, higher E\u00b0), so it displaces Br\u207b by oxidising it to Br\u2082 (1).' },
      { q: 'Explain why adding chlorine water to potassium iodide produces a brown colour.', marks: 2, markScheme: 'Cl\u2082 + 2KI \u2192 2KCl + I\u2082 (1). Iodine is produced which dissolves to give a brown/yellow solution (1).' },
      { q: 'State two benefits and one risk of adding fluoride to drinking water.', marks: 2, markScheme: 'Benefits: reduces tooth decay / strengthens enamel (1). Risk: excess fluoride can cause dental fluorosis / some people object to mass medication on ethical grounds (1).' },
      { q: 'Explain why chlorine water added to potassium astatide (KAt) would be expected to displace astatine.', marks: 2, markScheme: 'Chlorine is a stronger oxidising agent than astatine (higher up Group 7) (1). Cl\u2082 can oxidise At\u207b to At as it has a higher electronegativity and higher E\u00b0 (1).' },
      { q: 'State why excess hydrochloric acid is used in the test for sulfate ions with barium chloride.', marks: 1, markScheme: 'To prevent precipitation of barium carbonate or barium sulfite which would give false positives for sulfate (1).' },
      { q: 'A solution gives a yellow precipitate with AgNO\u2083 that is insoluble in ammonia. Identify the halide ion present.', marks: 1, markScheme: 'Iodide ion (I\u207b) (1).' },
      { q: 'Explain why magnesium hydroxide is used as an antacid.', marks: 2, markScheme: 'Mg(OH)\u2082 is a base that neutralises excess stomach acid (HCl) (1). Mg(OH)\u2082 + 2HCl \u2192 MgCl\u2082 + 2H\u2082O (1).' },
      { q: 'State why Group 2 elements are called "alkaline earth metals".', marks: 2, markScheme: 'Their oxides and hydroxides are alkaline/basic (1). They are found in the Earth\'s crust as minerals (1).' },
      { q: 'State the colours observed in the silver halide precipitates: AgCl, AgBr, AgI.', marks: 1, markScheme: 'AgCl = white, AgBr = cream/pale yellow, AgI = yellow (1).' },
      { q: 'Explain why the electronegativity of the halogens decreases down Group 7.', marks: 2, markScheme: 'Atomic radius increases down the group (1). The bonding pair of electrons is further from the nucleus with more shielding, so the halogen attracts electrons less strongly (1).' },
      { q: 'Write the equation for the reaction of Mg with oxygen and state the type of bonding in the product.', marks: 2, markScheme: '2Mg + O\u2082 \u2192 2MgO (1). Ionic bonding: Mg loses 2 electrons to form Mg\u00b2\u207a, O gains 2 electrons to form O\u00b2\u207b (1).' },
      { q: 'Describe the reaction of barium with water, including observations and the equation.', marks: 3, markScheme: 'Vigorous reaction with rapid effervescence (1). Ba dissolves and the solution becomes alkaline / milky if Ba(OH)\u2082 exceeds solubility (1). Ba + 2H\u2082O \u2192 Ba(OH)\u2082 + H\u2082 (1).' },
      { q: 'State and explain whether the reaction Mg + 2HCl \u2192 MgCl\u2082 + H\u2082 is a redox reaction.', marks: 2, markScheme: 'Yes, it is a redox reaction (1). Mg is oxidised (0 to +2) and H is reduced (+1 to 0) (1).' },
      { q: 'Explain why BaSO\u2084 is used in the test for sulfate ions rather than BaCO\u2083.', marks: 1, markScheme: 'BaSO\u2084 is insoluble in acid, confirming sulfate is present; BaCO\u2083 would dissolve in the acid used to acidify the solution (1).' },
      { q: 'Write the equation for the reaction of strontium with water and state the pH of the resulting solution.', marks: 2, markScheme: 'Sr + 2H\u2082O \u2192 Sr(OH)\u2082 + H\u2082 (1). Solution is alkaline, pH approximately 12\u201313 (1).' },
      { q: 'Explain why chlorine is a stronger oxidising agent than bromine.', marks: 2, markScheme: 'Chlorine has a smaller atomic radius and higher electronegativity than bromine (1). Cl atoms attract electrons more strongly, so Cl\u2082 is more readily reduced to Cl\u207b (1).' },
      { q: 'State the products when chlorine water is added to a solution of potassium bromide and describe the colour change.', marks: 2, markScheme: 'Cl\u2082 + 2KBr \u2192 2KCl + Br\u2082; chlorine displaces bromine (1). Solution changes from colourless to orange/brown as Br\u2082 is produced (1).' }
    ]
  },
  'I2': {
    name: 'Inorganic Chemistry II',
    questions: [
      { q: 'Define "transition metal" according to the AQA definition.', marks: 1, markScheme: 'A d-block element that forms at least one stable ion with a partially filled d-subshell (1).' },
      { q: 'Write the electron configuration of Cu and Cu\u00b2\u207a.', marks: 2, markScheme: 'Cu: [Ar] 3d\u00b9\u2070 4s\u00b9 (1). Cu\u00b2\u207a: [Ar] 3d\u2079 (1).' },
      { q: 'Explain why copper has the electron configuration [Ar] 3d\u00b9\u2070 4s\u00b9 rather than [Ar] 3d\u2079 4s\u00b2.', marks: 2, markScheme: 'A fully filled 3d subshell (3d\u00b9\u2070) is particularly stable (1). Energy gained from this stability outweighs the cost of having 4s half-filled (1).' },
      { q: 'State two properties of transition metals that differ from s-block metals.', marks: 2, markScheme: 'Form coloured compounds (1). Show variable oxidation states / act as catalysts / form complex ions (1).' },
      { q: 'Define "coordination number" and state the coordination number in [Cu(H\u2082O)\u2086]\u00b2\u207a.', marks: 2, markScheme: 'The number of coordinate bonds from ligands to the central metal ion (1). Coordination number = 6 (1).' },
      { q: 'State the shape of the complex [CuCl\u2084]\u00b2\u207b and explain why it is not octahedral.', marks: 2, markScheme: 'Tetrahedral (1). Cl\u207b ligands are large so only 4 can fit around the Cu\u00b2\u207a ion (1).' },
      { q: 'Define "ligand".', marks: 1, markScheme: 'A species that donates a lone pair of electrons to a central metal ion to form a coordinate/dative covalent bond (1).' },
      { q: 'Give two examples of bidentate ligands.', marks: 2, markScheme: 'Ethane-1,2-diamine (en / H\u2082NCH\u2082CH\u2082NH\u2082) (1). Ethanedioate (C\u2082O\u2084\u00b2\u207b / oxalate) (1).' },
      { q: 'State what is meant by a "multidentate ligand" and give one example.', marks: 2, markScheme: 'A ligand that forms more than two coordinate bonds to a metal ion (1). Example: EDTA (forms 6 coordinate bonds) (1).' },
      { q: 'Explain why [Ni(en)\u2083]\u00b2\u207a is more stable than [Ni(NH\u2083)\u2086]\u00b2\u207a (the chelate effect).', marks: 2, markScheme: 'When en replaces NH\u2083, 6 monodentate ligands are replaced by 3 bidentate ligands, releasing 3 extra free molecules (1). This increases entropy (\u0394S positive), making \u0394G more negative and the chelate complex more stable (1).' },
      { q: 'State the oxidation state of the metal in [CrCl\u2082(H\u2082O)\u2084]\u207a.', marks: 1, markScheme: 'Total charge = +1; Cl\u207b contributes \u22122; H\u2082O is neutral. So Cr = +1 + 2 = +3 (1).' },
      { q: 'Write the equation for the reaction of [Cu(H\u2082O)\u2086]\u00b2\u207a with excess ammonia.', marks: 1, markScheme: '[Cu(H\u2082O)\u2086]\u00b2\u207a + 4NH\u2083 \u2192 [Cu(NH\u2083)\u2084(H\u2082O)\u2082]\u00b2\u207a + 4H\u2082O (1).' },
      { q: 'State the colour change observed when excess NH\u2083 is added to [Cu(H\u2082O)\u2086]\u00b2\u207a.', marks: 1, markScheme: 'Pale blue precipitate dissolves to give a deep blue solution (1).' },
      { q: 'Explain why transition metal ions form coloured solutions.', marks: 2, markScheme: 'Ligands cause d-orbital splitting into two energy levels (1). Visible light is absorbed promoting a d electron between levels; the complementary colour is observed (1).' },
      { q: 'Explain why Zn\u00b2\u207a compounds are white/colourless.', marks: 2, markScheme: 'Zn\u00b2\u207a has a d\u00b9\u2070 configuration with all d orbitals fully occupied (1). No d-d transitions are possible so no visible light is absorbed (1).' },
      { q: 'State the colour of the following ions in aqueous solution: Fe\u00b2\u207a, Fe\u00b3\u207a, Cu\u00b2\u207a, Cr\u00b3\u207a.', marks: 2, markScheme: 'Fe\u00b2\u207a: pale green; Fe\u00b3\u207a: yellow/brown (1). Cu\u00b2\u207a: blue; Cr\u00b3\u207a: green/violet (1).' },
      { q: 'Describe the observation when NaOH is added to a solution containing Fe\u00b2\u207a ions.', marks: 2, markScheme: 'A green precipitate of Fe(OH)\u2082 forms (1). On standing in air, it turns brown/orange as Fe\u00b2\u207a is oxidised to Fe\u00b3\u207a (1).' },
      { q: 'Write the equation for the reaction of Fe\u00b3\u207a ions with NaOH.', marks: 1, markScheme: 'Fe\u00b3\u207a(aq) + 3OH\u207b(aq) \u2192 Fe(OH)\u2083(s) (brown precipitate) (1).' },
      { q: 'State the test for Fe\u00b3\u207a ions using thiocyanate and describe the positive result.', marks: 2, markScheme: 'Add KSCN / NaSCN solution (1). Blood-red colour forms due to [Fe(SCN)(H\u2082O)\u2085]\u00b2\u207a (1).' },
      { q: 'State why V\u2082O\u2085 is used as a catalyst in the Contact process. Name the reaction it catalyses.', marks: 2, markScheme: 'V\u2082O\u2085 catalyses the oxidation of SO\u2082 to SO\u2083: 2SO\u2082 + O\u2082 \u21cc 2SO\u2083 (1). It works by changing oxidation state: V\u2075\u207a is reduced then re-oxidised, providing an alternative lower-energy pathway (1).' },
      { q: 'State two examples of transition metals acting as catalysts, naming the metal and the process.', marks: 2, markScheme: 'Fe in the Haber process (N\u2082 + 3H\u2082 \u21cc 2NH\u2083) (1). V\u2082O\u2085 in the Contact process (2SO\u2082 + O\u2082 \u21cc 2SO\u2083) or Ni in hydrogenation of alkenes / Pt-Rh in catalytic converters (1).' },
      { q: 'Describe the acid-base behaviour of Al\u2082O\u2083. Write equations for its reactions with HCl and NaOH.', marks: 3, markScheme: 'Al\u2082O\u2083 is amphoteric (1). With HCl: Al\u2082O\u2083 + 6HCl \u2192 2AlCl\u2083 + 3H\u2082O (1). With NaOH: Al\u2082O\u2083 + 2NaOH + 3H\u2082O \u2192 2NaAl(OH)\u2084 / 2Na[Al(OH)\u2084] (1).' },
      { q: 'State the structure and bonding in SiO\u2082 and explain why it has a high melting point.', marks: 2, markScheme: 'Giant covalent / macromolecular structure with each Si bonded to 4 O atoms in a tetrahedral arrangement (1). Many strong Si-O covalent bonds must be broken, requiring a lot of energy (1).' },
      { q: 'Describe the acid-base character of Na\u2082O and SO\u2083, writing equations for their reactions with water.', marks: 3, markScheme: 'Na\u2082O is a basic oxide: Na\u2082O + H\u2082O \u2192 2NaOH (alkaline solution, pH ~14) (1). SO\u2083 is an acidic oxide: SO\u2083 + H\u2082O \u2192 H\u2082SO\u2084 (strongly acidic, pH ~1) (1). This shows the transition from basic to acidic character across Period 3 oxides (1).' },
      { q: 'Write the equation for the reaction of P\u2084O\u2081\u2080 with water.', marks: 1, markScheme: 'P\u2084O\u2081\u2080 + 6H\u2082O \u2192 4H\u2083PO\u2084 (1).' },
      { q: 'Explain why the melting point of NaCl is much higher than that of SiCl\u2084.', marks: 2, markScheme: 'NaCl is a giant ionic lattice with strong electrostatic attractions between Na\u207a and Cl\u207b ions (1). SiCl\u2084 is a simple molecular substance with only weak London forces between molecules (1).' },
      { q: 'Describe what happens when [Cr(H\u2082O)\u2086]\u00b3\u207a reacts with excess NaOH.', marks: 2, markScheme: 'First a green precipitate of Cr(OH)\u2083 forms (1). This dissolves in excess NaOH to form a dark green solution of [Cr(OH)\u2086]\u00b3\u207b as Cr(OH)\u2083 is amphoteric (1).' },
      { q: 'Write an equation for the ligand exchange reaction when concentrated HCl is added to [Co(H\u2082O)\u2086]\u00b2\u207a.', marks: 2, markScheme: '[Co(H\u2082O)\u2086]\u00b2\u207a + 4Cl\u207b \u21cc [CoCl\u2084]\u00b2\u207b + 6H\u2082O (1). Colour changes from pink to blue (1).' },
      { q: 'State the shape and bond angle in an octahedral complex.', marks: 1, markScheme: 'Octahedral with bond angles of 90\u00b0 (1).' },
      { q: 'State the shape and bond angle in a tetrahedral complex.', marks: 1, markScheme: 'Tetrahedral with bond angles of 109.5\u00b0 (1).' },
      { q: 'Explain why [Fe(H\u2082O)\u2086]\u00b3\u207a is more acidic than [Fe(H\u2082O)\u2086]\u00b2\u207a.', marks: 2, markScheme: 'Fe\u00b3\u207a has a higher charge and smaller radius than Fe\u00b2\u207a (higher charge density) (1). It polarises the O-H bonds in coordinated water molecules more, making it easier for H\u207a to be released (1).' },
      { q: 'Describe the colour and structure of the Period 3 chloride AlCl\u2083 when dissolved in water vs as an anhydrous solid.', marks: 2, markScheme: 'Anhydrous: covalent dimer Al\u2082Cl\u2086 (with dative bonds); exists as a solid that fumes in moist air (1). In water: dissolves to form [Al(H\u2082O)\u2086]\u00b3\u207a ions; the solution is acidic due to hydrolysis (1).' },
      { q: 'Write the ionic equation for the reaction of sodium with water and state the observations.', marks: 2, markScheme: '2Na(s) + 2H\u2082O(l) \u2192 2Na\u207a(aq) + 2OH\u207b(aq) + H\u2082(g) (1). Sodium floats, melts, moves on surface, fizzes; solution turns alkaline (1).' },
      { q: 'State the type of structure and bonding in MgCl\u2082 and explain its conductivity when molten.', marks: 2, markScheme: 'Giant ionic lattice with Mg\u00b2\u207a and Cl\u207b ions (1). When molten, ions are free to move and carry charge, so it conducts electricity (1).' },
      { q: 'Explain why NaOH is added dropwise to test for metal cations, rather than all at once.', marks: 2, markScheme: 'Adding dropwise allows observation of the initial precipitate colour for identification (1). Some precipitates are amphoteric and dissolve in excess NaOH, so the behaviour in excess helps confirm the cation (1).' },
      { q: 'State the colour of the precipitate formed when NaOH is added to a solution containing: (a) Cu\u00b2\u207a, (b) Fe\u00b2\u207a, (c) Fe\u00b3\u207a.', marks: 2, markScheme: 'Cu\u00b2\u207a: blue; Fe\u00b2\u207a: green (1). Fe\u00b3\u207a: brown/rust-coloured (1).' },
      { q: 'Write the equation showing how [Al(H\u2082O)\u2086]\u00b3\u207a acts as an acid.', marks: 1, markScheme: '[Al(H\u2082O)\u2086]\u00b3\u207a \u21cc [Al(H\u2082O)\u2085(OH)]\u00b2\u207a + H\u207a (1).' },
      { q: 'Explain why Al(OH)\u2083 dissolves in excess NaOH but Fe(OH)\u2083 does not.', marks: 2, markScheme: 'Al(OH)\u2083 is amphoteric: it reacts with excess OH\u207b to form the soluble aluminate ion [Al(OH)\u2084]\u207b (1). Fe(OH)\u2083 is not amphoteric; it does not react with excess NaOH and remains insoluble (1).' },
      { q: 'State the oxidation state of Mn in MnO\u2084\u207b.', marks: 1, markScheme: 'Mn is in oxidation state +7 (1).' },
      { q: 'Write the half-equation for the reduction of MnO\u2084\u207b in acidic solution.', marks: 1, markScheme: 'MnO\u2084\u207b + 8H\u207a + 5e\u207b \u2192 Mn\u00b2\u207a + 4H\u2082O (1).' },
      { q: 'Explain what is meant by "cis-trans isomerism" in octahedral complexes and give an example.', marks: 2, markScheme: 'Cis: identical ligands adjacent (90\u00b0); trans: identical ligands opposite (180\u00b0) (1). Example: [CrCl\u2082(H\u2082O)\u2084]\u207a can exist as cis (Cl atoms adjacent) and trans (Cl atoms opposite) isomers (1).' },
      { q: 'Explain how transition metals can have variable oxidation states.', marks: 2, markScheme: 'Transition metals have similar energies for 3d and 4s electrons (1). Different numbers of electrons can be lost/used in bonding, giving stable ions with different charges (1).' },
      { q: 'Name the complex [Cr(NH\u2083)\u2084Cl\u2082]\u207a using IUPAC nomenclature.', marks: 2, markScheme: 'Tetraamminedichlorochromium(III) ion (1). Correct use of prefixes and naming ligands in alphabetical order (1).' },
      { q: 'State why cisplatin [Pt(NH\u2083)\u2082Cl\u2082] is used as an anti-cancer drug but the trans isomer is not effective.', marks: 2, markScheme: 'Cisplatin has the correct geometry to bind to DNA, forming cross-links that prevent cell division (1). The trans isomer cannot form these same cross-links due to the different spatial arrangement of the ligands (1).' },
      { q: 'Describe the trend in acid-base character of Period 3 chlorides when added to water.', marks: 3, markScheme: 'NaCl and MgCl\u2082 dissolve to give neutral or slightly acidic solutions (ionic chlorides) (1). AlCl\u2083 reacts vigorously / fumes, giving an acidic solution (pH ~3) due to hydrolysis of [Al(H\u2082O)\u2086]\u00b3\u207a (1). SiCl\u2084 and PCl\u2085 react vigorously with water (hydrolysis) to form HCl and the oxide/acid, giving strongly acidic solutions (1).' },
      { q: 'State the colour of potassium dichromate(VI) and potassium chromate(VI) solutions.', marks: 1, markScheme: 'K\u2082Cr\u2082O\u2087: orange; K\u2082CrO\u2084: yellow (1).' },
      { q: 'Write the equation for the conversion of dichromate to chromate in alkaline solution.', marks: 1, markScheme: 'Cr\u2082O\u2087\u00b2\u207b + 2OH\u207b \u21cc 2CrO\u2084\u00b2\u207b + H\u2082O (1).' },
      { q: 'State the oxidation state of vanadium in VO\u00b2\u207a, VO\u00b2\u207a, V\u00b3\u207a, and V\u00b2\u207a.', marks: 2, markScheme: 'VO\u2082\u207a: +5; VO\u00b2\u207a: +4 (1). V\u00b3\u207a: +3; V\u00b2\u207a: +2 (1).' },
      { q: 'State the colours associated with vanadium in oxidation states +5, +4, +3, and +2.', marks: 2, markScheme: '+5 (VO\u2082\u207a): yellow; +4 (VO\u00b2\u207a): blue (1). +3 (V\u00b3\u207a): green; +2 (V\u00b2\u207a): violet/lilac (1).' },
      { q: 'Explain why scandium is not classed as a transition metal despite being in the d-block.', marks: 2, markScheme: 'Sc only forms Sc\u00b3\u207a ions with configuration [Ar] 3d\u2070 (1). This has no partially filled d-subshell, so it does not meet the definition of a transition metal (1).' }
    ]
  },
  'O1': {
    name: 'Organic Chemistry I',
    questions: [
      { q: 'Define "homologous series".', marks: 1, markScheme: 'A family of organic compounds with the same functional group and general formula, each member differing by CH\u2082 (1).' },
      { q: 'Define "structural isomers".', marks: 1, markScheme: 'Compounds with the same molecular formula but different structural arrangements of atoms (1).' },
      { q: 'Draw and name the three structural isomers of C\u2085H\u2081\u2082.', marks: 3, markScheme: 'Pentane: CH\u2083CH\u2082CH\u2082CH\u2082CH\u2083 (1). 2-methylbutane: CH\u2083CH(CH\u2083)CH\u2082CH\u2083 (1). 2,2-dimethylpropane: C(CH\u2083)\u2084 (1).' },
      { q: 'State the general formula of alkanes and alkenes.', marks: 1, markScheme: 'Alkanes: CnH\u2082n+\u2082; Alkenes: CnH\u2082n (1).' },
      { q: 'Explain why alkanes are relatively unreactive.', marks: 2, markScheme: 'C-C and C-H bonds are strong and non-polar (1). No region of high electron density to attract electrophiles or nucleophiles (1).' },
      { q: 'State the conditions for the free radical substitution of methane with chlorine.', marks: 1, markScheme: 'UV light / sunlight (1).' },
      { q: 'Write the initiation step for the free radical chlorination of methane.', marks: 1, markScheme: 'Cl\u2082 \u2192 2Cl\u2022 (homolytic fission by UV light) (1).' },
      { q: 'Write the two propagation steps for the free radical chlorination of methane.', marks: 2, markScheme: 'Cl\u2022 + CH\u2084 \u2192 CH\u2083\u2022 + HCl (1). CH\u2083\u2022 + Cl\u2082 \u2192 CH\u2083Cl + Cl\u2022 (1).' },
      { q: 'Write one termination step for the free radical chlorination of methane.', marks: 1, markScheme: 'Any of: Cl\u2022 + Cl\u2022 \u2192 Cl\u2082 or CH\u2083\u2022 + Cl\u2022 \u2192 CH\u2083Cl or CH\u2083\u2022 + CH\u2083\u2022 \u2192 C\u2082H\u2086 (1).' },
      { q: 'Explain what is meant by "electrophilic addition" and state why alkenes undergo this type of reaction.', marks: 2, markScheme: 'A reaction where an electrophile is attracted to a region of high electron density and adds across a double bond (1). Alkenes have a C=C bond with a high electron density \u03c0 bond that attracts electrophiles (1).' },
      { q: 'Write the equation for the reaction of ethene with bromine.', marks: 1, markScheme: 'CH\u2082=CH\u2082 + Br\u2082 \u2192 CH\u2082BrCH\u2082Br (1,2-dibromoethane) (1).' },
      { q: 'Describe how bromine water is used to test for an alkene and state the observation.', marks: 2, markScheme: 'Add bromine water to the alkene and shake (1). Bromine water decolourises from orange/brown to colourless (1).' },
      { q: 'State the reagents and conditions for the hydration of ethene to form ethanol.', marks: 2, markScheme: 'Steam at high temperature (300\u00b0C) and high pressure (60\u201370 atm) (1). Phosphoric acid (H\u2083PO\u2084) catalyst (1).' },
      { q: 'Define "primary alcohol" and give one example.', marks: 1, markScheme: 'An alcohol where the OH group is on a carbon attached to one (or no) other carbon atom; example: ethanol CH\u2083CH\u2082OH (1).' },
      { q: 'State the reagent and conditions for oxidising a primary alcohol to an aldehyde.', marks: 2, markScheme: 'Acidified potassium dichromate (K\u2082Cr\u2082O\u2087 / H\u2082SO\u2084) (1). Heat and distil (to remove the aldehyde as it forms, preventing further oxidation) (1).' },
      { q: 'State the reagent and conditions for oxidising a primary alcohol to a carboxylic acid.', marks: 2, markScheme: 'Acidified potassium dichromate (K\u2082Cr\u2082O\u2087 / H\u2082SO\u2084) (1). Heat under reflux (to ensure complete oxidation) (1).' },
      { q: 'Explain why tertiary alcohols cannot be oxidised by acidified dichromate.', marks: 2, markScheme: 'Tertiary alcohols have no hydrogen on the carbon bearing the OH group (1). Oxidation requires removal of H from this carbon, which is not possible in a tertiary alcohol (1).' },
      { q: 'Describe the elimination reaction of an alcohol to form an alkene. State reagent and conditions.', marks: 2, markScheme: 'Heat the alcohol with concentrated H\u2082SO\u2084 or concentrated H\u2083PO\u2084 (or pass vapour over hot Al\u2082O\u2083) (1). Water is eliminated: e.g. CH\u2083CH\u2082OH \u2192 CH\u2082=CH\u2082 + H\u2082O (1).' },
      { q: 'State the reagent for converting a halogenoalkane to an alcohol and give the conditions.', marks: 2, markScheme: 'Aqueous NaOH (1). Heat under reflux; nucleophilic substitution (1).' },
      { q: 'State the reagent for converting a halogenoalkane to an amine and give the conditions.', marks: 2, markScheme: 'Excess concentrated ammonia (1). Heat in a sealed tube; nucleophilic substitution (1).' },
      { q: 'State the reagent for converting a halogenoalkane to a nitrile and give the conditions.', marks: 2, markScheme: 'KCN in ethanol/water (1). Heat under reflux; nucleophilic substitution (increases chain length by 1 carbon) (1).' },
      { q: 'Describe the mechanism for the nucleophilic substitution of 1-bromopropane with OH\u207b (SN2).', marks: 3, markScheme: 'OH\u207b is the nucleophile with a lone pair (1). OH\u207b attacks the \u03b4+ C from the opposite side to the C-Br bond (curly arrow from OH\u207b to C) (1). C-Br bond breaks (curly arrow from bond to Br), Br\u207b is the leaving group; one-step mechanism (1).' },
      { q: 'State Markovnikov\'s rule.', marks: 1, markScheme: 'When HX adds to an unsymmetrical alkene, the hydrogen adds to the carbon already carrying more hydrogen atoms (1).' },
      { q: 'State and explain whether E or Z isomerism is possible in but-2-ene.', marks: 2, markScheme: 'Yes, E/Z isomerism is possible because the two groups on each C of the C=C are different (H and CH\u2083 on each) (1). Z-but-2-ene has both CH\u2083 groups on the same side; E-but-2-ene has them on opposite sides (1).' },
      { q: 'Describe the test to distinguish an aldehyde from a ketone using Tollens\' reagent.', marks: 2, markScheme: 'Warm with Tollens\' reagent (silver nitrate in aqueous ammonia) (1). Aldehyde: silver mirror forms on tube; ketone: no reaction (1).' },
      { q: 'Describe the test to distinguish an aldehyde from a ketone using Fehling\'s solution.', marks: 2, markScheme: 'Warm with Fehling\'s solution (blue copper(II) tartrate complex) (1). Aldehyde: blue solution changes to red/brick-red precipitate (Cu\u2082O); ketone: stays blue (1).' },
      { q: 'State what is meant by "mass spectrum fragmentation" and identify the fragment at m/z = 29 in the mass spectrum of propanal.', marks: 2, markScheme: 'Molecular ions break into fragments in the mass spectrometer; each fragment gives a peak at its m/z value (1). m/z = 29 corresponds to CHO\u207a (the aldehyde fragment) (1).' },
      { q: 'State the wavenumber range for the O-H absorption in an alcohol in an IR spectrum.', marks: 1, markScheme: 'Broad absorption at approximately 3230\u20133550 cm\u207b\u00b9 (1).' },
      { q: 'State the wavenumber range for the C=O absorption in an IR spectrum.', marks: 1, markScheme: 'Strong sharp absorption at approximately 1680\u20131750 cm\u207b\u00b9 (1).' },
      { q: 'Name the type of reaction when ethanol reacts with ethanoic acid in the presence of an acid catalyst.', marks: 1, markScheme: 'Esterification / condensation (1).' },
      { q: 'Write the equation for the esterification of methanol with propanoic acid.', marks: 1, markScheme: 'CH\u2083OH + CH\u2083CH\u2082COOH \u21cc CH\u2083CH\u2082COOCH\u2083 + H\u2082O (1).' },
      { q: 'State why concentrated sulfuric acid is used as a catalyst in esterification.', marks: 1, markScheme: 'Acts as a catalyst by protonating the carboxylic acid to increase the electrophilicity of the C=O carbon (1).' },
      { q: 'Explain why the rate of hydrolysis of halogenoalkanes follows the order: iodo > bromo > chloro.', marks: 2, markScheme: 'C-I bond is the weakest (longest, lowest bond enthalpy) (1). Weaker bonds are broken more easily, so iodoalkanes react fastest (1).' },
      { q: 'Describe the combustion of ethanol and write the equation.', marks: 2, markScheme: 'Ethanol burns in air with a clean blue flame (1). C\u2082H\u2085OH + 3O\u2082 \u2192 2CO\u2082 + 3H\u2082O (1).' },
      { q: 'State the conditions needed for the fermentation of glucose to produce ethanol.', marks: 2, markScheme: 'Yeast as a biological catalyst, temperature approximately 30\u201340\u00b0C (1). Anaerobic conditions (absence of oxygen); C\u2086H\u2081\u2082O\u2086 \u2192 2C\u2082H\u2085OH + 2CO\u2082 (1).' },
      { q: 'Compare the production of ethanol by fermentation and by hydration of ethene. State one advantage of each.', marks: 3, markScheme: 'Fermentation: uses renewable resources (sugar cane/crops); low temperature process; batch process (1). Hydration: continuous process; produces pure ethanol; fast rate (1). Fermentation advantage: renewable feedstock; hydration advantage: high purity/fast production (1).' },
      { q: 'State the structural formula of the product when propan-1-ol is heated with acidified K\u2082Cr\u2082O\u2087 under reflux.', marks: 1, markScheme: 'CH\u2083CH\u2082COOH (propanoic acid) (1).' },
      { q: 'State the structural formula of the product when propan-2-ol is heated with acidified K\u2082Cr\u2082O\u2087.', marks: 1, markScheme: 'CH\u2083COCH\u2083 (propanone) (1).' },
      { q: 'Explain what is meant by "percentage yield" and suggest two reasons why yields are often less than 100%.', marks: 2, markScheme: 'Percentage yield = (actual yield / theoretical yield) \u00d7 100 (1). Reasons: incomplete reaction / reversible reaction, side reactions, product lost during purification/transfer (1).' },
      { q: 'State the type of reaction when 2-bromopropane reacts with ethanolic KOH and name the product.', marks: 2, markScheme: 'Elimination reaction (1). Product: propene (CH\u2083CH=CH\u2082) with KBr and H\u2082O as by-products (1).' },
      { q: 'Explain the difference between the reaction of a halogenoalkane with aqueous NaOH and with ethanolic NaOH.', marks: 2, markScheme: 'Aqueous NaOH: nucleophilic substitution, OH\u207b replaces halogen to form an alcohol (1). Ethanolic NaOH: elimination, OH\u207b acts as a base removing H and the halogen, forming an alkene (1).' },
      { q: 'Draw the mechanism for the electrophilic addition of Br\u2082 to ethene.', marks: 3, markScheme: 'Br-Br bond is polarised as it approaches the electron-rich C=C (induced dipole) (1). Curly arrow from C=C to \u03b4+Br; Br-Br bond breaks heterolytically forming Br\u207b and a carbocation intermediate (1). Curly arrow from Br\u207b to C\u207a forming 1,2-dibromoethane (1).' },
      { q: 'State what is meant by a "curly arrow" in organic mechanisms.', marks: 1, markScheme: 'A curly arrow represents the movement of a pair of electrons (1).' },
      { q: 'State what is meant by "homolytic fission" and "heterolytic fission".', marks: 2, markScheme: 'Homolytic: bond breaks so each atom gets one electron, forming two radicals (1). Heterolytic: bond breaks so both electrons go to one atom, forming a cation and an anion (1).' },
      { q: 'Name the type of reaction and the product when ethanol is heated with excess acidified K\u2082Cr\u2082O\u2087 under distillation.', marks: 2, markScheme: 'Oxidation (1). Product: ethanal (CH\u2083CHO), collected by distillation before further oxidation occurs (1).' },
      { q: 'What is the IUPAC name for CH\u2083CHBrCH\u2083?', marks: 1, markScheme: '2-bromopropane (1).' },
      { q: 'What is the IUPAC name for CH\u2083CH(OH)CH\u2082CH\u2083?', marks: 1, markScheme: 'Butan-2-ol (1).' },
      { q: 'State two methods for increasing the yield of an esterification reaction.', marks: 2, markScheme: 'Use excess of one reactant to shift equilibrium to the right (1). Remove water (product) as it forms, or use a dehydrating agent (1).' },
      { q: 'State the IUPAC name for CH\u2083CH=CHCH\u2083 and state whether E/Z isomerism is possible.', marks: 2, markScheme: 'But-2-ene (1). Yes, E/Z isomerism is possible as each C of the double bond has two different groups attached (1).' },
      { q: 'Explain why the C=C bond in ethene is stronger than a single C-C bond but not twice as strong.', marks: 2, markScheme: 'The double bond consists of one sigma bond (strong head-on overlap) and one pi bond (weaker sideways overlap) (1). The pi bond has less effective overlap than the sigma bond, so the total bond enthalpy is less than twice a single C-C bond (1).' }
    ]
  },
  'O2': {
    name: 'Organic Chemistry II',
    questions: [
      { q: 'State the reagent used to test for a carbonyl group (C=O in aldehydes and ketones).', marks: 1, markScheme: '2,4-dinitrophenylhydrazine (Brady\'s reagent / 2,4-DNPH) (1).' },
      { q: 'State the observation for a positive 2,4-DNPH test.', marks: 1, markScheme: 'Yellow/orange precipitate forms (a 2,4-dinitrophenylhydrazone) (1).' },
      { q: 'How can the melting point of a 2,4-DNPH derivative be used to identify a specific carbonyl compound?', marks: 2, markScheme: 'Recrystallise the precipitate and measure its melting point (1). Compare with a data table of known 2,4-DNPH derivative melting points to identify the original compound (1).' },
      { q: 'State the reagent and conditions for reducing a ketone to a secondary alcohol.', marks: 2, markScheme: 'NaBH\u2084 (sodium borohydride) (1). In aqueous or methanol solution at room temperature (1).' },
      { q: 'State the reagent and conditions for reducing a carbonyl to an alcohol using LiAlH\u2084.', marks: 2, markScheme: 'LiAlH\u2084 (lithium aluminium hydride) (1). In dry ether solvent under anhydrous conditions (1).' },
      { q: 'Describe the mechanism for nucleophilic addition of NaBH\u2084 to ethanal.', marks: 3, markScheme: 'H\u207b from BH\u2084\u207b attacks the \u03b4+ carbon of C=O (curly arrow from H\u207b to C) (1). C=O \u03c0 bond breaks, electrons move to O forming alkoxide intermediate (1). Protonation by water/acid to form ethanol (CH\u2083CH\u2082OH) (1).' },
      { q: 'State what is meant by a "chiral centre".', marks: 1, markScheme: 'A carbon atom bonded to four different groups/atoms (1).' },
      { q: 'Explain why the nucleophilic addition of HCN to ethanal produces a racemic mixture.', marks: 2, markScheme: 'The CN\u207b can attack the planar C=O from either above or below with equal probability (1). This produces equal amounts of both enantiomers (R and S), giving a racemic mixture (optically inactive) (1).' },
      { q: 'Define "racemic mixture".', marks: 1, markScheme: 'An equal mixture of both enantiomers of a chiral compound, which is optically inactive because the rotations cancel out (1).' },
      { q: 'State the reagent and conditions for the reaction of a carboxylic acid with an alcohol to form an ester.', marks: 2, markScheme: 'Heat under reflux with a concentrated sulfuric acid catalyst (1). Reversible reaction producing an ester and water (1).' },
      { q: 'Write the equation for the hydrolysis of an ester (methyl ethanoate) with dilute NaOH.', marks: 1, markScheme: 'CH\u2083COOCH\u2083 + NaOH \u2192 CH\u2083COONa + CH\u2083OH (1).' },
      { q: 'Explain why alkaline hydrolysis of esters goes to completion but acid hydrolysis does not.', marks: 2, markScheme: 'Alkaline hydrolysis is irreversible because the carboxylate ion formed (RCOO\u207b) is very stable and does not readily react back (1). Acid hydrolysis is reversible because both the acid and alcohol products can recombine (1).' },
      { q: 'State the reagent for converting a carboxylic acid to an acyl chloride.', marks: 1, markScheme: 'SOCl\u2082 (thionyl chloride) or PCl\u2085 (phosphorus pentachloride) (1).' },
      { q: 'State one advantage of using acyl chlorides instead of carboxylic acids for making esters and amides.', marks: 1, markScheme: 'Acyl chlorides are more reactive than carboxylic acids; reactions go to completion / are faster / not reversible (1).' },
      { q: 'Write the equation for the reaction of ethanoyl chloride with water.', marks: 1, markScheme: 'CH\u2083COCl + H\u2082O \u2192 CH\u2083COOH + HCl (1).' },
      { q: 'Write the equation for the reaction of ethanoyl chloride with ethanol.', marks: 1, markScheme: 'CH\u2083COCl + C\u2082H\u2085OH \u2192 CH\u2083COOC\u2082H\u2085 + HCl (1).' },
      { q: 'Write the equation for the reaction of ethanoyl chloride with ammonia.', marks: 1, markScheme: 'CH\u2083COCl + 2NH\u2083 \u2192 CH\u2083CONH\u2082 + NH\u2084Cl (1).' },
      { q: 'State the conditions for the nitration of benzene and write the equation.', marks: 2, markScheme: 'Concentrated HNO\u2083 and concentrated H\u2082SO\u2084 at 50\u00b0C (1). C\u2086H\u2086 + HNO\u2083 \u2192 C\u2086H\u2085NO\u2082 + H\u2082O (1).' },
      { q: 'State the electrophile in the nitration of benzene and show how it is generated.', marks: 2, markScheme: 'The electrophile is the nitronium ion NO\u2082\u207a (1). Generated by: HNO\u2083 + H\u2082SO\u2084 \u2192 NO\u2082\u207a + HSO\u2084\u207b + H\u2082O (1).' },
      { q: 'Describe the mechanism for the nitration of benzene.', marks: 3, markScheme: 'NO\u2082\u207a electrophile attacks the \u03c0 electron system of benzene ring (curly arrow from ring to NO\u2082\u207a) (1). Intermediate carbocation formed (cyclohexadienyl cation) with loss of delocalisation (1). H\u207a is lost to restore aromaticity: curly arrow from C-H bond back to ring; H\u207a reacts with HSO\u2084\u207b to regenerate H\u2082SO\u2084 (1).' },
      { q: 'State the conditions for Friedel-Crafts acylation of benzene.', marks: 2, markScheme: 'Acyl chloride (e.g. CH\u2083COCl) with AlCl\u2083 catalyst (1). Anhydrous conditions, heat under reflux (1).' },
      { q: 'Explain why benzene undergoes substitution rather than addition reactions.', marks: 2, markScheme: 'Benzene has a delocalised \u03c0 electron system which gives it extra stability (1). Addition would break the delocalised system and reduce stability; substitution preserves it (1).' },
      { q: 'State the conditions for reducing nitrobenzene to phenylamine.', marks: 2, markScheme: 'Tin (Sn) and concentrated HCl (1). Heat under reflux, then add NaOH to liberate the free amine (1).' },
      { q: 'Explain why phenylamine is a weaker base than ammonia.', marks: 2, markScheme: 'The lone pair on nitrogen in phenylamine is partially delocalised into the benzene ring (1). This makes it less available to accept a proton, so phenylamine is a weaker base (1).' },
      { q: 'Explain why ethylamine is a stronger base than ammonia.', marks: 2, markScheme: 'The ethyl group is electron-releasing (positive inductive effect) (1). This pushes electron density onto nitrogen, making the lone pair more available to accept a proton (1).' },
      { q: 'State how amines can be prepared from halogenoalkanes.', marks: 2, markScheme: 'React the halogenoalkane with excess concentrated ammonia (1). Heat in a sealed tube; nucleophilic substitution replaces the halogen with NH\u2082 (1).' },
      { q: 'Define "amino acid" and draw the general structure.', marks: 2, markScheme: 'A molecule containing both an amine group (-NH\u2082) and a carboxylic acid group (-COOH) (1). General structure: H\u2082N-CHR-COOH where R is the side chain (1).' },
      { q: 'Explain what a "zwitterion" is and state the pH at which amino acids exist mainly as zwitterions.', marks: 2, markScheme: 'A zwitterion is a molecule with both a positive and negative charge (NH\u2083\u207a and COO\u207b) but overall neutral (1). At the isoelectric point (specific pH for each amino acid) (1).' },
      { q: 'State the type of polymerisation that produces nylon and identify the linkage formed.', marks: 2, markScheme: 'Condensation polymerisation (1). Amide / peptide linkage (-CONH-) formed with loss of water / HCl (1).' },
      { q: 'State the type of polymerisation that produces a polyester and identify the linkage formed.', marks: 2, markScheme: 'Condensation polymerisation (1). Ester linkage (-COO-) formed with loss of water (1).' },
      { q: 'State one environmental issue with non-biodegradable addition polymers and one solution.', marks: 2, markScheme: 'They persist in landfill / pollute oceans for hundreds of years as they are not broken down (1). Solution: recycling, incineration for energy recovery, or developing biodegradable alternatives (1).' },
      { q: 'Explain why condensation polymers are more readily biodegradable than addition polymers.', marks: 2, markScheme: 'Condensation polymers contain ester or amide linkages that can be hydrolysed by water/enzymes (1). Addition polymers have only C-C bonds in the backbone which are not easily broken by biological processes (1).' },
      { q: 'In \u00b9H NMR, state what determines the chemical shift of a proton.', marks: 1, markScheme: 'The chemical environment / electron density around the proton determines its chemical shift (1).' },
      { q: 'In \u00b9H NMR, state what information is given by the number of peaks in a spectrum.', marks: 1, markScheme: 'The number of different proton environments in the molecule (1).' },
      { q: 'In \u00b9H NMR, state what information is given by the integration / relative peak areas.', marks: 1, markScheme: 'The relative number of protons in each environment (1).' },
      { q: 'State the n+1 rule for \u00b9H NMR splitting and apply it to predict the splitting pattern for CH\u2083CH\u2082OH.', marks: 3, markScheme: 'n+1 rule: a proton with n equivalent neighbouring protons is split into n+1 peaks (1). CH\u2083: 3H, split by 2H on CH\u2082 \u2192 triplet (1). CH\u2082: 2H, split by 3H on CH\u2083 \u2192 quartet (1).' },
      { q: 'State the chemical shift range for an aldehyde proton (R-CHO) in \u00b9H NMR.', marks: 1, markScheme: '\u03b4 9.0\u201310.0 ppm (1).' },
      { q: 'State the chemical shift range for a carboxylic acid proton (R-COOH) in \u00b9H NMR.', marks: 1, markScheme: '\u03b4 10.0\u201312.0 ppm (1).' },
      { q: 'Explain how D\u2082O can be used in NMR to identify O-H and N-H protons.', marks: 2, markScheme: 'D\u2082O is added and the spectrum re-recorded (1). O-H and N-H peaks disappear because the protons exchange with deuterium (D), which does not show in the \u00b9H NMR spectrum (1).' },
      { q: 'In \u00b9\u00b3C NMR, state what information is given by the number of peaks.', marks: 1, markScheme: 'The number of different carbon environments in the molecule (1).' },
      { q: 'State how many peaks would appear in the \u00b9\u00b3C NMR spectrum of ethanol (CH\u2083CH\u2082OH).', marks: 1, markScheme: 'Two peaks (two different carbon environments: CH\u2083 and CH\u2082OH) (1).' },
      { q: 'State how many peaks would appear in the \u00b9\u00b3C NMR spectrum of propanone (CH\u2083COCH\u2083).', marks: 1, markScheme: 'Two peaks (C=O and two equivalent CH\u2083 groups) (1).' },
      { q: 'Explain what is meant by a "chromophore" and how it relates to the colour of organic dyes.', marks: 2, markScheme: 'A chromophore is a part of a molecule responsible for absorbing UV or visible light (typically a system of conjugated double bonds) (1). When visible light is absorbed, the complementary colour is seen; in dyes, extended conjugation shifts absorption into the visible range (1).' },
      { q: 'State the reagents and conditions for converting benzene to phenol via a diazonium salt.', marks: 3, markScheme: 'Step 1: Nitrate benzene then reduce to phenylamine (Sn/conc HCl, then NaOH) (1). Step 2: Form diazonium salt: phenylamine + NaNO\u2082 + HCl below 10\u00b0C to form C\u2086H\u2085N\u2082\u207aCl\u207b (1). Step 3: Warm the diazonium salt with water to form phenol + N\u2082 (1).' },
      { q: 'Explain why phenol is a stronger acid than ethanol.', marks: 2, markScheme: 'When phenol loses H\u207a, the phenoxide ion (C\u2086H\u2085O\u207b) is stabilised by delocalisation of the negative charge into the benzene ring (1). The ethoxide ion has no such stabilisation, so the O-H bond in ethanol is harder to break (1).' },
      { q: 'State two uses of diazonium coupling reactions.', marks: 2, markScheme: 'Formation of azo dyes (strongly coloured compounds used in textiles and food colouring) (1). Azo coupling involves reaction of diazonium salt with a phenol or aromatic amine to form an azo compound (R-N=N-R\') (1).' },
      { q: 'State the reagent that reacts with an acyl chloride to form an amide.', marks: 1, markScheme: 'Ammonia (NH\u2083) or a primary amine (RNH\u2082) (1).' },
      { q: 'Name the organic product of the reaction: CH\u2083COCl + CH\u2083NH\u2082.', marks: 1, markScheme: 'N-methylethanamide (CH\u2083CONHCH\u2083) (1).' },
      { q: 'Describe how you would distinguish between propanal and propanone using Tollens\' reagent.', marks: 2, markScheme: 'Warm both with Tollens\' reagent (ammoniacal silver nitrate) (1). Propanal gives a silver mirror; propanone gives no reaction (1).' },
      { q: 'State the conditions for the formation of a diazonium salt from phenylamine.', marks: 2, markScheme: 'React phenylamine with NaNO\u2082 and dilute HCl (1). Temperature must be kept below 10\u00b0C to prevent decomposition of the diazonium salt (1).' }
    ]
  }
};
